132: func getPreScoreState(cycleState *framework.CycleState) (*preScoreState, error) {
133: 	c, err := cycleState.Read(preScoreStateKey)
134: 	if err != nil {
135: 		return nil, fmt.Errorf("reading %q from cycleState: %w", preScoreStateKey, err)
136: 	}
137: 
