396: func hasRestartableInitContainer(pod *v1.Pod) bool {
397: 	for _, c := range pod.Spec.InitContainers {
398: 		if c.RestartPolicy != nil && *c.RestartPolicy == v1.ContainerRestartPolicyAlways {
399: 			return true
400: 		}
401: 	}
402: 	return false
403: }
